class MyStack {
private:
    std::queue<int> q1;
    std::queue<int> q2;
    bool isQ1Current;

public:
    MyStack() : isQ1Current(true) {}

    void push(int x) {
        if (isQ1Current) {
            q1.push(x);
        } else {
            q2.push(x);
        }
    }

    int pop() {
        if (isQ1Current) {
            while (q1.size() > 1) {
                q2.push(q1.front());
                q1.pop();
            }
            int top = q1.front();
            q1.pop();
            isQ1Current = false;
            return top;
        } else {
            while (q2.size() > 1) {
                q1.push(q2.front());
                q2.pop();
            }
            int top = q2.front();
            q2.pop();
            isQ1Current = true;
            return top;
        }
    }

    int top() {
        if (isQ1Current) {
            while (q1.size() > 1) {
                q2.push(q1.front());
                q1.pop();
            }
            return q1.front();
        } else {
            while (q2.size() > 1) {
                q1.push(q2.front());
                q2.pop();
            }
            return q2.front();
        }
    }

    bool empty() {
        return q1.empty() && q2.empty();
    }
};

